// 204_SOLAR_BACKUP_DIMENSIONAMENTO_INVERSOR
const potencia_critica_simultanea_kw = $input.item.json.potencia_critica_simultanea_kw || 0;
const margem_tecnica = 1.25; // 25% margem

let potencia_inversor_minima_kw = potencia_critica_simultanea_kw * margem_tecnica;

// Regra de Motores/Pico (se aplicável)
if ($input.item.json.tem_motores) {
    potencia_inversor_minima_kw *= 1.5; // Fator simplificado para placeholder se não avaliado
}

$input.item.json.potencia_inversor_minima_kw = parseFloat(potencia_inversor_minima_kw.toFixed(2));

return $input.item;
